function normalizeQuery(queryText) {
  let q = queryText;
  const CONTRACTIONS = {
    "ain't": "is not",
    "aren't": "are not",
    "can't": "cannot",
    "couldn't": "could not",
    "didn't": "did not",
    "doesn't": "does not",
    "don't": "do not",
    "hadn't": "had not",
    "hasn't": "has not",
    "haven't": "have not",
    "he's": "he is",
    "i'd": "i would",
    "i'll": "i will",
    "i'm": "i am",
    "i've": "i have",
    "isn't": "is not",
    "it's": "it is",
    "let's": "let us",
    "shouldn't": "should not",
    "that's": "that is",
    "they're": "they are",
    "they've": "they have",
    "wasn't": "was not",
    "we're": "we are",
    "we've": "we have",
    "weren't": "were not",
    "what's": "what is",
    "won't": "will not",
    "wouldn't": "would not",
    "you're": "you are",
  };
  const KEYS = Object.keys(CONTRACTIONS).sort((a, b) => b.length - a.length);
  const PATTERN = new RegExp("\\b(" + KEYS.join("|") + ")\\b", "g");
  q = q.toLowerCase();
  q = q.replace(/\u2019/g, "'");
  q = q.replace(PATTERN, (m) => CONTRACTIONS[m]);
  q = q.trim();
  return q;
}

